package metrics

import (
	"strings"
	"testing"
)

func TestHistogramObserveBoundaryValuesAreCumulative(t *testing.T) {
	r := New()
	h := r.NewHistogram("boundary_histogram", "boundary test", []float64{1, 5, 10})

	for _, v := range []float64{1, 5, 10} {
		h.Observe(v)
	}

	out := writeMetric(h)
	requireLines(t, out,
		`boundary_histogram_bucket{le="1"} 1`,
		`boundary_histogram_bucket{le="5"} 2`,
		`boundary_histogram_bucket{le="10"} 3`,
		`boundary_histogram_bucket{le="+Inf"} 3`,
		`boundary_histogram_sum 16`,
		`boundary_histogram_count 3`,
	)
}

func TestHistogramObserveNonBoundaryValuesKeepPlacement(t *testing.T) {
	r := New()
	h := r.NewHistogram("range_histogram", "range test", []float64{1, 5, 10})

	for _, v := range []float64{0.5, 4.999, 5.001, 11, 12} {
		h.Observe(v)
	}

	out := writeMetric(h)
	requireLines(t, out,
		`range_histogram_bucket{le="1"} 1`,
		`range_histogram_bucket{le="5"} 2`,
		`range_histogram_bucket{le="10"} 3`,
		`range_histogram_bucket{le="+Inf"} 5`,
		`range_histogram_sum 33.5`,
		`range_histogram_count 5`,
	)
}

func writeMetric(m Metric) string {
	var b strings.Builder
	m.Write(&b)
	return b.String()
}

func requireLines(t *testing.T, out string, lines ...string) {
	t.Helper()
	for _, line := range lines {
		if !strings.Contains(out, line+"\n") {
			t.Fatalf("missing line %q in output:\n%s", line, out)
		}
	}
}

